#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7,inv2=(mod+1)/2;

int n,m,w;
char s[15];

void add(int &x,long long y){
    x=(x+y)%mod;
}

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

struct Node{
    int a[1<<12];
    void FWT(){
        for(int i=0;i<w;i++)
            for(int j=0;j<1<<w;j++)
                if(s[i]=='|' && ((j>>i)&1))
                    add(a[j],a[j-(1<<i)]);
                else if(s[i]=='&' && !((j>>i)&1))
                    add(a[j],a[j+(1<<i)]);
                else if(s[i]=='^'){
                    if((j>>i)&1)
                        add(a[j],a[j-(1<<i)]+a[j]);
                    else
                        add(a[j],mod-a[j+(1<<i)]);
                }
    }
    void IFWT(){
        for(int i=0;i<w;i++)
            for(int j=(1<<w)-1;j>=0;j--)
                if(s[i]=='|' && ((j>>i)&1))
                    add(a[j],mod-a[j-(1<<i)]);
                else if(s[i]=='&' && !((j>>i)&1))
                    add(a[j],mod-a[j+(1<<i)]);
                else if(s[i]=='^'){
                    if((j>>i)&1)
                        a[j]=1ll*inv2*(a[j]-a[j-(1<<i)])%mod;
                    else
                        add(a[j],a[j+(1<<i)]);
                }
    }
}d[75][75];

int main(){
    scanf("%d%d",&n,&m);
    scanf("%s",s);
    w=strlen(s);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        add(d[u][v].a[w],mod-1);
        add(d[v][u].a[w],mod-1);
        add(d[u][u].a[w],1);
        add(d[v][v].a[w],1);
    }
    for(int i=2;i<=n;i++)
        for(int j=2;j<=n;j++)
            d[i][j].FWT();
    for(int i=2;i<=n;i++)
        for(int j=i+1;j<=n;j++){
            Node num;
            for(int k=0;k<1<<w;k++)
                num.a[k]=1ll*d[j][i].a[k]*qpow(d[i][i].a[k],mod-2)%mod;
            for(int k=2;k<=n;k++)
                for(int l=0;l<1<<w;l++)
                    d[j][k].a[l]=(d[j][k].a[l]-1ll*d[i][k].a[l]*num.a[l])%mod;
        }
    Node res=d[2][2];
    for(int i=3;i<=n;i++)
        for(int j=0;j<1<<w;j++)
            res.a[j]=1ll*res.a[j]*d[i][i].a[j]%mod;
    res.IFWT();
    for(int i=(1<<w)-1;i>=0;i--)
        if(res.a[i]){
            printf("%d\n",i);
            return 0;
        }
    puts("-1");
    return 0;
}
